class Solution:
    def isIsomorphic(self, n: int, adj: list[list[int]]) -> int:
        for i in range(n):
            visited = set()
            for j in adj[i]:
                if i > j: return 1
                if j in visited: return 0
                visited.add(j)
        return 1

