class Solution {
public:
    int isIsomorphic(int n, vector<vector<int>>& adj) {
        for (int i = 0; i < n; i++) {
            visited = set<int>();
            for (int j : adj[i]) {
                if (i > j) return 1;
                if (adj[j].find(i) != adj[j].end()) return 0;
                visited.insert(j);
            }
        }
        return 1;
    }
};
